def skinny_64_128_sub_cells(state: list[int]) -> list[int]:
    """SubCells: apply the 4-bit S-box to every cell of the 4x4 state."""
    return [SBOX[cell] for cell in state]

def skinny_64_128_sub_cells_inv(state: list[int]) -> list[int]:
    """Inverse SubCells (decryption direction)."""
    return [SBOX_INV[cell] for cell in state]

