def skinny_64_128_key_to_tweakey_state(master_key: int) -> list[list[int]]:
    """Split the 128-bit key into TWEAKEY_BLOCKS=2 16-cell tweakey arrays."""
    return [
        skinny_64_128_block_to_state((master_key >> (BLOCK_SIZE * (TWEAKEY_BLOCKS - 1 - z))) & BLOCK_MASK)
        for z in range(TWEAKEY_BLOCKS)
    ]

