def skinny_64_128_generate_round_tweakeys_acc(
    tweakey_state: list[list[int]], round_index: int, acc: list[list[int]]
) -> list[list[int]]:
    """Recursive accumulator for the round-tweakey schedule (mirrors the
    Isabelle recursive helper skinny_64_128_generate_round_tweakeys_acc)."""
    if round_index >= ROUNDS - 1:
        return acc
    new_state, rkm = skinny_64_128_update_tweakey_state(tweakey_state)
    return skinny_64_128_generate_round_tweakeys_acc(new_state, round_index + 1, acc + [rkm])

def skinny_64_128_generate_round_tweakeys(master_key: int) -> list[list[int]]:
    """Generate the round-key XOR material (8 cells: rows 0,1) for all ROUNDS rounds."""
    tweakey_state = skinny_64_128_key_to_tweakey_state(master_key)
    rk0 = skinny_64_128_initial_round_key(tweakey_state)
    return skinny_64_128_generate_round_tweakeys_acc(tweakey_state, 0, [rk0])

