definition skinny_64_128_encrypt_round ::
  "4 word list \<Rightarrow> nat \<Rightarrow> 4 word list \<Rightarrow> 4 word list" where
  "skinny_64_128_encrypt_round state round_index round_key_material =
     (let s1 = skinny_64_128_sub_cells state;
          rc = skinny_64_128_rc ! (round_index mod length skinny_64_128_rc);
          c0 = of_nat (rc mod 16) :: 4 word;
          c1 = of_nat ((rc div 16) mod 4) :: 4 word;
          s2 = s1[0 := xor (s1 ! 0) c0, 4 := xor (s1 ! 4) c1, 8 := xor (s1 ! 8) 2];
          s3 = map (\<lambda>p. xor (fst p) (snd p)) (zip (take 8 s2) round_key_material) @ drop 8 s2;
          s4 = skinny_64_128_shift_rows s3
      in skinny_64_128_mix_columns s4)"

definition skinny_64_128_decrypt_round ::
  "4 word list \<Rightarrow> nat \<Rightarrow> 4 word list \<Rightarrow> 4 word list" where
  "skinny_64_128_decrypt_round state round_index round_key_material =
     (let s1 = skinny_64_128_mix_columns_inv state;
          s2 = skinny_64_128_shift_rows_inv s1;
          s3 = map (\<lambda>p. xor (fst p) (snd p)) (zip (take 8 s2) round_key_material) @ drop 8 s2;
          rc = skinny_64_128_rc ! (round_index mod length skinny_64_128_rc);
          c0 = of_nat (rc mod 16) :: 4 word;
          c1 = of_nat ((rc div 16) mod 4) :: 4 word;
          s4 = s3[0 := xor (s3 ! 0) c0, 4 := xor (s3 ! 4) c1, 8 := xor (s3 ! 8) 2]
      in skinny_64_128_sub_cells_inv s4)"

