def skinny_64_128_encrypt_rounds_iterate(state: list[int], round_keys: list[list[int]], i: int) -> list[int]:
    """Recursive encryption iterator over all ROUNDS rounds."""
    if i >= ROUNDS:
        return state
    next_state = skinny_64_128_encrypt_round(state, i, round_keys[i])
    return skinny_64_128_encrypt_rounds_iterate(next_state, round_keys, i + 1)

def skinny_64_128_decrypt_rounds_iterate(state: list[int], round_keys: list[list[int]], i: int) -> list[int]:
    """Recursive decryption iterator: rounds consumed ROUNDS-1 down to 0."""
    if i >= ROUNDS:
        return state
    round_index = ROUNDS - 1 - i
    next_state = skinny_64_128_decrypt_round(state, round_index, round_keys[round_index])
    return skinny_64_128_decrypt_rounds_iterate(next_state, round_keys, i + 1)

def skinny_64_128_encrypt(plaintext: int, master_key: int) -> int:
    """Encrypt one 64-bit block under one 128-bit tweakey."""
    round_keys = skinny_64_128_generate_round_tweakeys(master_key)
    state = skinny_64_128_block_to_state(plaintext & BLOCK_MASK)
    state = skinny_64_128_encrypt_rounds_iterate(state, round_keys, 0)
    return skinny_64_128_state_to_block(state)

